import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { attendanceAPI } from '../services/api';
import toast from 'react-hot-toast';

const STUDENTS_MOCK = ['Aarav Sharma','Priya Singh','Rohit Gupta','Ananya Patel','Dev Kumar','Sakshi Verma','Arjun Mishra','Neha Tiwari','Vikram Joshi','Kavya Rao'];

export default function Attendance() {
  const today = new Date().toISOString().split('T')[0];
  const [att, setAtt] = useState(() => Object.fromEntries(STUDENTS_MOCK.map((n,i)=>([i,'present']))));

  const s = (color) => ({ padding:'2px 10px', borderRadius:20, fontSize:11, fontWeight:600, background:color==='green'?'#D1FAE5':color==='red'?'#FEE2E2':'#FEF3C7', color:color==='green'?'#065F46':color==='red'?'#991B1B':'#92400E' });

  const counts = Object.values(att).reduce((a,v)=>({...a,[v]:(a[v]||0)+1}),{});

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:20}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Attendance</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>{today} · Class 8A</p></div>
        <button onClick={()=>toast.success(`Attendance saved! Present: ${counts.present||0}, Absent: ${counts.absent||0}`)}
          style={{padding:'8px 18px',background:'#2D1B69',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}}>
          💾 Save Attendance
        </button>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'2fr 1fr',gap:16}}>
        <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
          <div style={{padding:'12px 16px',background:'#F9FAFB',borderBottom:'0.5px solid #E5E7EB',display:'grid',gridTemplateColumns:'1fr 70px 70px 70px',gap:8,fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>
            <span>Student</span><span style={{textAlign:'center',color:'#059669'}}>Present</span><span style={{textAlign:'center',color:'#DC2626'}}>Absent</span><span style={{textAlign:'center',color:'#D97706'}}>Leave</span>
          </div>
          {STUDENTS_MOCK.map((name,i)=>(
            <div key={i} style={{padding:'10px 16px',borderBottom:'0.5px solid #F3F4F6',display:'grid',gridTemplateColumns:'1fr 70px 70px 70px',gap:8,alignItems:'center'}}>
              <div style={{display:'flex',alignItems:'center',gap:8}}>
                <div style={{width:28,height:28,borderRadius:7,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#2D1B69'}}>{name[0]}</div>
                <span style={{fontSize:13,fontWeight:500}}>{name}</span>
              </div>
              {['present','absent','leave'].map(status=>(
                <div key={status} style={{textAlign:'center'}}>
                  <input type="radio" name={`att-${i}`} checked={att[i]===status} onChange={()=>setAtt({...att,[i]:status})}
                    style={{width:16,height:16,accentColor:status==='present'?'#059669':status==='absent'?'#DC2626':'#D97706',cursor:'pointer'}}/>
                </div>
              ))}
            </div>
          ))}
        </div>

        <div style={{display:'flex',flexDirection:'column',gap:14}}>
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:18}}>
            <div style={{fontWeight:600,fontSize:13,marginBottom:14}}>📊 Summary</div>
            {[['Present','present','#059669','#D1FAE5'],['Absent','absent','#DC2626','#FEE2E2'],['Leave','leave','#D97706','#FEF3C7']].map(([label,key,c,bg])=>(
              <div key={key} style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'8px 0',borderBottom:'0.5px solid #F3F4F6'}}>
                <span style={{fontSize:13,color:'#374151'}}>{label}</span>
                <span style={{padding:'3px 12px',borderRadius:20,background:bg,color:c,fontWeight:700,fontSize:13}}>{counts[key]||0}</span>
              </div>
            ))}
            <div style={{marginTop:14,padding:12,background:'#EDE9F8',borderRadius:10,textAlign:'center'}}>
              <div style={{fontSize:22,fontWeight:700,color:'#2D1B69'}}>{Math.round(((counts.present||0)/STUDENTS_MOCK.length)*100)}%</div>
              <div style={{fontSize:11,color:'#6B7280'}}>Attendance Rate</div>
            </div>
          </div>

          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:18}}>
            <div style={{fontWeight:600,fontSize:13,marginBottom:10}}>🚀 Quick Mark</div>
            <div style={{display:'flex',flexDirection:'column',gap:8}}>
              <button onClick={()=>setAtt(Object.fromEntries(STUDENTS_MOCK.map((_,i)=>([i,'present']))))}
                style={{padding:'8px',background:'#D1FAE5',color:'#065F46',border:'none',borderRadius:8,fontSize:12,fontWeight:600,cursor:'pointer'}}>✅ All Present</button>
              <button onClick={()=>setAtt(Object.fromEntries(STUDENTS_MOCK.map((_,i)=>([i,'absent']))))}
                style={{padding:'8px',background:'#FEE2E2',color:'#991B1B',border:'none',borderRadius:8,fontSize:12,fontWeight:600,cursor:'pointer'}}>❌ All Absent</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
